create table dirkspzm32.isi_tor_cfg (
    sid                      varchar2(2 char) not null enable,
    firma_nr                 varchar2(2 char) not null enable,
    tor_id_lesegeraet        varchar2(15 char) not null enable,
    tor_id_lesegeraet_typ    varchar2(15 char),
    tor_prae                 varchar2(15 char),
    tor_post                 varchar2(15 char),
    tor_name                 varchar2(30 char) not null enable,
    tor_typ                  varchar2(15 char),
    com_name                 varchar2(15 char),
    tor_visuname             varchar2(15 char),
    tor_alle                 varchar2(1 char) default 'F' not null enable,
    tor_ablauf               varchar2(20 char),
    tor_offen_zeit           number default 5 not null enable,
    tor_dauer_offen          varchar2(1 char) default 'F' not null enable,
    tor_dauer_offen_mo       varchar2(1 char) default 'T' not null enable,
    tor_dauer_offen_di       varchar2(1 char) default 'T' not null enable,
    tor_dauer_offen_mi       varchar2(1 char) default 'T' not null enable,
    tor_dauer_offen_do       varchar2(1 char) default 'T' not null enable,
    tor_dauer_offen_fr       varchar2(1 char) default 'T' not null enable,
    tor_dauer_offen_sa       varchar2(1 char) default 'F' not null enable,
    tor_dauer_offen_so       varchar2(1 char) default 'F' not null enable,
    tor_dauer_offen_feiertag varchar2(1 char) default 'F' not null enable,
    tor_dauer_offen_von      date,
    tor_dauer_offen_bis      date,
    tor_warte_n_senden       number(*, 12) default 200 not null enable,
    tor_warte_antwort        number(*, 12) default 100 not null enable,
    tor_warte_daten          number(*, 12) default 50 not null enable,
    tor_warte_execute        number(*, 12) default 250 not null enable,
    tor_rs485_adresse        number(*, 5) default 255 not null enable,
    sched_res_id             number(*, 0) default 0 not null enable
);

alter table dirkspzm32.isi_tor_cfg
    add constraint pk_isi_tor_cfg primary key ( tor_id_lesegeraet,
                                                tor_rs485_adresse )
        using index enable;

alter table dirkspzm32.isi_tor_cfg
    add constraint uk_isi_tor_cfg_coms unique ( com_name,
                                                tor_rs485_adresse )
        using index enable;


